mapper.select:
select ld.log_document_id, ld.document_id, ld.space_id, ld.user_id, ld.action, ld.comment, ld.create_time, u.username, u.given_name, d.name as document_name, d.type as document_type from mw_log_document ld left join mw_user u on u.user_id = ld.user_id left join mw_document d on d.document_id = ld.document_id where 1 = 1 and ld.user_id = #{userId}
and (ld.comment like concat('%', #{keyword}, '%') or d.name like concat('%', #{keyword}, '%'))
order by ld.log_document_id desc
